mapper.select:
SELECT * FROM orders
WHERE status = 'PENDING_PAYMENT'
  AND created_at <= #{cutoff}

mapper.update:
UPDATE orders
SET status = 'RETURN_APPROVED',
    return_approved_at = NOW(),
    updated_at = NOW()
WHERE id = #{id}
  AND status = #{currentStatus}

UPDATE orders
SET status = #{status},
    updated_at = NOW()
WHERE id = #{id}
  AND status = #{currentStatus}

UPDATE orders
SET status = 'REFUNDED',
    return_reason = CASE
        WHEN #{reason} IS NULL OR #{reason} = '' THEN return_reason
        ELSE #{reason}
    END,
    refunded_at = NOW(),
    updated_at = NOW()
WHERE id = #{id}
  AND status = #{currentStatus}
